var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카일 웡이라...... 진짜 이름도 비슷하네요.","JPN":"カイル・ウォンか……本当に名前も似てるんですね。","ENG":"Kyle Wong. Even your name's similar.","TWN":"凱爾嗎……真的連名字也很像呢。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이쯤 되면 무슨 운명의 장난 같은데?","JPN":"ここまでくると、何かの運命のイタズラみたいな？","ENG":"This has to be some sort of trick.","TWN":"這是什麼命運的玩笑嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"뭘 보고 계신 거죠?","JPN":"何を見ているんです？","ENG":"What are you looking at?","TWN":"妳在看什麼？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아, 카린 양. 카린 양의 이세계 오빠로 추정되는 분의 신분증을 살펴보고 있었어요.","JPN":"あ、カリンさん。カリンさんのお兄ちゃん風の方の身分証を見ていました。","ENG":"Oh, Karin. I was looking at the identification card of your otherworldly brother.","TWN":"啊，卡琳小姐。我看了下卡琳小姐異世界哥哥的身份證。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"놀라지 마시라, 짜잔! 이 분도 델타 세븐 소속이라고요!","JPN":"なんと、じゃじゃーん！　この方もデルタセブン所属なんです！","ENG":"Don't be surprised—tah-dah! Even he's in Delta Seven!","TWN":"請不要被嚇到哦，鏘鏘！這位也隸屬第七三角洲部隊！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이쪽 세계에도 델타 세븐이라는 부대가 있나 본데요?","JPN":"この世界にもデルタセブンという部隊があるようですよ？","ENG":"There must be a unit with that same name here, huh?","TWN":"看來這個世界也有叫作第七三角洲的部隊耶？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"여기 델타 세븐에는 누가 있는지 궁금하지 않아요?","JPN":"ここのデルタセブンにいるのは誰か、気になりませんか？","ENG":"Don't you want to know who might be in this Delta Seven?","TWN":"妳不好奇這邊的第七三角洲部隊裡有誰嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어쩌면 알만한 얼굴들이 더 있을 수도......","JPN":"もしかしたら、顔見知りが他にもいるかも……","ENG":"Perhaps there are more familiar faces.","TWN":"說不定會有更多熟悉的面孔……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......우연일 뿐이겠죠. 그런 쓸데없는 호기심을 충족할 여유는 없습니다.","JPN":"……偶然にすぎません。そんな無駄な好奇心に構っている暇はありません。","ENG":"This just has to be a coincidence. We don't have time to satisfy our personal curiosity.","TWN":"……應該只是偶然吧。現在可沒時間去滿足妳那沒用的好奇心。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨가 시간을 벌어준 덕분에 이 시설들의 통제권을 확보할 수 있었습니다.","JPN":"シノンさんが時間稼ぎしてくれたおかげで、この施設の統制権を確保できました。","ENG":"Shiyoung, because you stalled them, I was able to take control over these facilities.","TWN":"多虧周時雨小姐爭取了時間，我可以獲取這座設施的控制權了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"예측대로 이건 고도로 발전된 이터니움 반응로 같아요.","JPN":"予想通り、これは高度の発展を遂げたエタニウム反応炉のようです。","ENG":"This is just as I expected. I think it's a highly advanced Eternium reactor.","TWN":"不出所料，這是一個高度發達的永恆之金反應爐。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이터니움 반응로?","JPN":"エタニウム反応炉？","ENG":"An Eternium reactor?","TWN":"永恆之金反應爐？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네. 저희 델타 세븐에서도 구상 단계에 머물러 있던...... 이론상의 동력기관이죠.","JPN":"はい、我がデルタセブンでも構想レベルに留まっていた……理論上の動力機関なんです。","ENG":"Yes. It's a theoretical engine that my Delta Seven has only dreamed of.","TWN":"沒錯。我們第七三角洲部隊也只停留在構思階段……理論上這是一個動力機關。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니까 반응로를 다시 가동하면, 우리 세계와 이곳 간의 차원 통로를 확보할 수 있어요.","JPN":"要するに、反応炉を再稼働すれば、私たちの世界と、この世界との次元間通路を確保できます。","ENG":"If we reactivate this reactor, we can open up a passage between here and our world.","TWN":"所以只要重新啟動反應爐，就可以確保我們的世界和這裡之間的次元通道。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"와, 그거 참 좋은 소식이네요.","JPN":"おお、それは嬉しいニュースですね。","ENG":"Wow, that's great news!","TWN":"哇喔，那可真是個好消息呢。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"원래는 에너지원으로 쓸 고순도 이터니움을 현지 조달한다는 황당한 계획이었는데 말이죠.","JPN":"元々はエネルギー原として使うための高純度エタニウムを現地調達するという、とんでもない計画だったのに。","ENG":"Our original plan was a reckless one, to self-supply high-purity Eternium for energy generation purposes.","TWN":"不過，高純度永恆之金原來是作為能量源使用的，他們竟然現場調配，真是個荒唐的計畫呢。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이걸로 생환 가능성이 5% 정도는 올랐겠죠?","JPN":"これで生きて帰れる可能性が5％くらいは上がったでしょうか？","ENG":"This should have increased our chances of survival by 5%, right?","TWN":"這下我們生還的可能性應該上升了5%左右吧？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"좋은 소식......","JPN":"嬉しいニュース……","ENG":"Great news...","TWN":"好消息……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네. 저희에겐 좋은 소식이기야 하지만......","JPN":"ええ、私たちにとって嬉しいニュースなのは、間違いないですけど……","ENG":"Yes, it's great news to us, but...","TWN":"對，對我們來說算是好消息，不過……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......당신들은 대체 누굽니까?","JPN":"……あなた方の正体はいったい何ですか？","ENG":"Who on earth are you?","TWN":"……你們到底是誰？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"설마 이런 짓을 하고도 무사히 넘어갈 수 있다고 생각하는 건 아니겠죠?","JPN":"まさかこんなことをしでかして、ただで済むとは思ってないですよね？","ENG":"You don't really think you can get away with this, do you?","TWN":"做了這種事，你們不會以為自己能夠安然脫身吧？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"뭐, 뭐죠? 이 사람 아직 살아 있는 건가요?","JPN":"な、何ですか？　この人、まだ生きているんですか？","ENG":"W-what? Why is he still alive?","TWN":"什，什麼？這個人還活著嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"......거 남이 들으면 오해할 소리는 삼가 해 주세요.","JPN":"……そんな誤解を招くような言い方は控えてくださいね。","ENG":"You shouldn't say things that could be so easily misunderstood.","TWN":"……請不要說讓人誤會的話。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"제가 무슨 어둠의 암살자도 아니고.","JPN":"別に殺戮マシンじゃあるまいし、","ENG":"If others heard it, they might think I was your assassin.","TWN":"我又不是什麼潛藏在黑暗中的暗殺者。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"사람은 함부로 해치지 않는다고요.","JPN":"むやみに他人を殺害したりしませんから。","ENG":"I don't hurt people unnecessarily.","TWN":"我不會隨便傷害人類的。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그것도 카린 양을 꼭 닮은 귀여운 소년에게 손을 대다니, 완전 무리죠.","JPN":"しかも、カリンさんそっくりなキュートな少年に手をかけるなんて、無理無理。","ENG":"And there's no way I'd lay a hand on such a cute boy who looks just like you.","TWN":"況且還是長得跟卡琳小姐這麼像的可愛少年，我完全沒辦法下手啊。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아, 그러고 보니 전투 패턴도 카린 양과 비슷하더라고요.","JPN":"あ、そういえば、戦闘パターンもカリンさんと似てましたよ？","ENG":"Ah, speaking of which, he even fights like you, Karin.","TWN":"啊，而且他的戰鬥方式也和卡琳小姐差不多。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"알고 싸워서 다행이지 몰랐으면 그대로 붙잡혔을 거에요.","JPN":"戦闘パターンを知らなかったら、そのまま捕まってたでしょうね。","ENG":"I'm glad I noticed that early on, or I would have been captured by him.","TWN":"幸好戰鬥前知道這些，不然我可能當場就被逮捕囉。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"제, 제 전투 패턴이 어떻다는 거죠?","JPN":"わ、私の戦闘パターンがどうだと言うんです？","ENG":"H-he fights like me? How?","TWN":"妳、妳說我的戰鬥方式怎麼樣？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"생각이 너무 많고 대범함이 부족한 지리멸렬 형?","JPN":"考えすぎで大胆さが足りない支離滅裂型ですかね？","ENG":"Both of you think too much and hesitate when you shouldn't.","TWN":"想太多又缺乏膽量，雜亂無章的戰鬥方式？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신이 너무 무모한 거겠지!","JPN":"あなたが無謀すぎるんです！","ENG":"And you don't think at all!","TWN":"是妳太魯莽了吧！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"가만히 듣고 있자니 무슨 말을 하는 건지 점점 더 모르겠군요.","JPN":"聞けば聞くほど、ますます釈然としません。","ENG":"The more I listen to you, the more confused I am.","TWN":"越聽越不懂你們在說些什麼了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"마치 알고 있던 것처럼 시설 내의 방어 시스템을 탈취해서 우릴 격리구역에 가둔 것도 그렇고,","JPN":"まるで知っていたかのように、施設内の防御システムを乗っ取って、我々を隔離エリアに閉じ込めたことも、","ENG":"You took over our defense system as if you knew how it worked, and locked us in this isolation area.","TWN":"但就好像事前知道一樣。奪取設施內的防禦系統，把我們關在隔離區域也是，"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그...... 외모까지......","JPN":"その……見た目も……","ENG":"On top of that, the way you look...","TWN":"還有……外貌也是……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"대체 당신들의 목적이 뭡니까?","JPN":"いったいあなた方の目的は何ですか？","ENG":"What is it that you want?","TWN":"你們的目的到底是什麼？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이터니움 반응로를 탈취해서...... 무슨 짓을 꾸미는 거죠?","JPN":"エタニウム反応炉を奪って……何をしようと？","ENG":"What are you trying to do with our Eternium reactor?","TWN":"你們奪取永恆之金反應爐……有什麼陰謀？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아, 그건 말이죠......","JPN":"あ、それは……","ENG":"Ah, that's—","TWN":"啊，這個呀……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨!","JPN":"シノンさん！","ENG":"Shiyoung!","TWN":"時雨小姐！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"괜찮아요, 괜찮아. 어차피 곧 알게 될 건데 딱히 비밀이랄 것도 없잖아요?","JPN":"大丈夫、大丈夫。じきにわかることですし、特に秘密にすることでもないでしょう？","ENG":"It's okay. He's going to know sooner or later. It's not even a secret, is it?","TWN":"沒事，沒事。反正他們很快就會知道了，也沒什麼需要特別保密的吧？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그러니까 우리가 맡은 임무는 말이죠, 으음...... 막상 설명하려니 좀 복잡한데......","JPN":"ですから、私たちの任務はですね、うーん……いざ説明するとなると難しいな……","ENG":"So, our mission is to, erm... It's a bit complicated now that I want to explain it...","TWN":"所以說我們的任務是，嗯……要解釋還有點複雜呢……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"간단히 말하자면 일종의 쓰레기 무단 투기라고 할까요?","JPN":"簡単に言えば、ちょっとしたゴミの不法投棄といいましょうか？","ENG":"To put it simply, it's illegal dumping.","TWN":"簡單來說，可以算是一種隨意傾倒垃圾的行為？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};